#include <bits/stdc++.h>
using namespace std;
const int N=100005;
struct node 
{
    int l,r,id,id2;
    node(int a=0,int b=0,int c=0,int d=0):l(min(a,b)),r(max(a,b)),id(c),id2(d)
    {
    }
} q[N*4];
long long n,id[N],ans,a[N],visl[N],visr[N],block,ans2[N],m,cnt,L,R;
bool cmp(node x,node y)
{
    if(id[x.l]==id[y.l]) return x.r<y.r;
    return x.l<y.l;
}
void ml(int num)
{
    if(num)
    {
        visl[a[L+1]]++;
        ans+=visr[a[L+1]];
        L++;
        return ;
    }
    visl[a[L]]--;
    ans-=visr[a[L]];
    L--;
}
void mr(int num)
{
    if(num)
    {
        visr[a[R+1]]++;
        ans+=visl[a[R+1]];
        R++;
        return ;
    }
    visr[a[R]]--;
    ans-=visl[a[R]];
    R--;
}
int main()
{
    cin>>n;
    block=sqrt(n);
    for(int i=1;i<=n;i++)
    {
        cin>>a[i];
        id[i]=i/block+1;
    }
    cin>>m;
    for(int i=1;i<=m;i++)
    {
        int l,r,l2,r2;
        cin>>l>>r>>l2>>r2;
        q[++cnt]=node(r,r2,i,1);
        q[++cnt]=node(r,l2-1,i,0);
        q[++cnt]=node(l-1,r2,i,0);
		q[++cnt]=node(l-1,l2-1,i,1);
    }
    sort(q+1,q+1+cnt,cmp);
    for(int i=1;i<=cnt;i++)
    {
        int tl=q[i].l,tr=q[i].r;
		while(L<tl) ml(1);
		while(L>tl) ml(0);
		while(R<tr) mr(1);
		while(R>tr) mr(0);
        if(q[i].id2) ans2[q[i].id]+=ans;
        else ans2[q[i].id]-=ans;     
    }
    for(int i=1;i<=m;i++) cout<<ans2[i]<<'\n';
    return 0;
}
